class Contact:
    def __init__(self, name: str, number: int):
        self.checkNumber(number)
        self._name = name
        self._number = number

    @property
    def name(self) -> str:
        return self._name

    @property
    def number(self) -> int:
        return self._number

    def checkNumber(self, number: int) -> bool:
        s = str(number)
        if len(s) != 8:
            raise InvalidContactException('Contact number must contain exactly 8 digits')
        if s[0] not in ('6', '8', '9'):
            raise InvalidContactException('Contact number must start with a 6, 8 or 9')
        return True

    def __str__(self) -> str:
        return f'Name: {self._name}   Number: {self._number}'
```

