class PhoneBook:
    def __init__(self):
        self._contacts = []

    def searchContact(self, name: str):
        for c in self._contacts:
            if c.name == name:
                return c
        return None

    def searchNumber(self, number: int) -> bool:
        for c in self._contacts:
            if c.number == number:
                return True
        return False

    def addContact(self, name: str, number: int) -> bool:
        # Check duplicate name (case insensitive)
        for c in self._contacts:
            if c.name.lower() == name.lower():
                raise InvalidContactException(f'Contact with name {name} already exists')
        # Check duplicate number
        if self.searchNumber(number):
            raise InvalidContactException(f'Contact number {number} already exists')
        # Create Contact (may raise InvalidContactException if format is invalid)
        new_contact = Contact(name, number)
        self._contacts.append(new_contact)
        return True

    def removeContact(self, name: str) -> bool:
        contact = self.searchContact(name)
        if contact:
            self._contacts.remove(contact)
            return True
        return False

    def __str__(self) -> str:
        sorted_contacts = sorted(self._contacts, key=lambda c: c.name)
        return '\n'.join(str(c) for c in sorted_contacts)
